import numpy as np

class ZZFeatureMap:
    def __init__(self, n_qubits, reps=1):
        self.n_qubits = n_qubits
        self.reps = reps
        self.dim = 2 ** n_qubits

    def encode(self, x):
        # Start with |+⟩^n
        state = np.ones(self.dim, dtype=complex) / np.sqrt(self.dim)

        for _ in range(self.reps):
            # Single-qubit Z rotations
            for i in range(self.dim):
                bits = format(i, f'0{self.n_qubits}b')
                phase = 0
                for q in range(self.n_qubits):
                    if bits[q] == '1' and q < len(x):
                        phase += x[q]
                state[i] *= np.exp(1j * phase)

            # ZZ interactions
            for i in range(self.dim):
                bits = format(i, f'0{self.n_qubits}b')
                phase = 0
                for q1 in range(self.n_qubits):
                    for q2 in range(q1 + 1, self.n_qubits):
                        if bits[q1] == '1' and bits[q2] == '1':
                            x1 = x[q1] if q1 < len(x) else 0
                            x2 = x[q2] if q2 < len(x) else 0
                            phase += x1 * x2
                state[i] *= np.exp(1j * phase)

        return state

    def kernel(self, x1, x2):
        state1 = self.encode(x1)
        state2 = self.encode(x2)
        return np.abs(np.vdot(state1, state2)) ** 2

zz = ZZFeatureMap(n_qubits=2, reps=2)
x1 = [0.5, 0.3]
x2 = [0.8, 0.6]

print(f'k(x1, x1) = {zz.kernel(x1, x1):.6f}')
print(f'k(x1, x2) = {zz.kernel(x1, x2):.6f}')

import numpy as np

class PeriodicFeatureMap:
    def __init__(self, n_qubits, reps=1):
        self.n_qubits = n_qubits
        self.reps = reps
        self.dim = 2 ** n_qubits

    def encode(self, x):
        state = np.ones(self.dim, dtype=complex) / np.sqrt(self.dim)

        for _ in range(self.reps):
            for i in range(self.dim):
                bits = format(i, f'0{self.n_qubits}b')
                phase = 0

                # Periodic single-qubit encoding
                for q in range(self.n_qubits):
                    if bits[q] == '1' and q < len(x):
                        # Use sin and cos for periodicity
                        phase += np.sin(x[q]) + np.cos(x[q])

                # Periodic pairwise
                for q1 in range(self.n_qubits):
                    for q2 in range(q1 + 1, self.n_qubits):
                        if bits[q1] == '1' and bits[q2] == '1':
                            if q1 < len(x) and q2 < len(x):
                                phase += np.sin(x[q1]) * np.sin(x[q2])

                state[i] *= np.exp(1j * phase)

        return state

    def kernel(self, x1, x2):
        state1 = self.encode(x1)
        state2 = self.encode(x2)
        return np.abs(np.vdot(state1, state2)) ** 2

fm = PeriodicFeatureMap(n_qubits=2, reps=1)

x1 = [0, 0]
x2 = [2*np.pi, 2*np.pi]
x3 = [np.pi, np.pi]

print(f'k(0, 2π) = {fm.kernel(x1, x2):.6f}')
print(f'k(0, π) = {fm.kernel(x1, x3):.6f}')
print(f'\nPeriodicity check:')
print(f'sin(0) = sin(2π) = {np.sin(0):.4f}')
print(f'cos(0) = cos(2π) = {np.cos(0):.4f}')
